import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "./styleHeader.css";
import "./styleDarkMode.css";

export default function Header() {
    const [theme, setTheme] = useState(() => {
        const savedTheme = localStorage.getItem('theme');
        if (savedTheme === 'dark' || savedTheme === 'light') {
            return savedTheme;
        }
        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    });

    const isDarkMode = theme === 'dark';

    useEffect(() => {
        document.documentElement.setAttribute('data-theme', theme);
        localStorage.setItem('theme', theme);
    }, [theme]);

    const toggleTheme = () => {
        setTheme(isDarkMode ? 'light' : 'dark');
    };

    return (
        <header className="header">
            <nav className="navbar">
                <div className="navbar-links">
                    <Link to="/portfolio" className="navbar-link">Portfolio</Link>
                    <Link to="/cv" className="navbar-link">CV</Link>
                </div>
                <div className="navbar-title">
                    <Link to="/" className="navbar-title-link">GRENOT BASTIEN</Link>
                </div>
                <div className="navbar-social">
                    <a href="https://www.linkedin.com/in/bastiengrnt/" target="_blank" rel="noreferrer">
                        <img src="/Logo/linkedin.svg" alt="LinkedIn" className="social-icon" />
                    </a>
                    <a href="https://github.com/BastienGRNT" target="_blank" rel="noreferrer">
                        <img src="/Logo/github.svg" alt="Github" className="social-icon" />
                    </a>
                    <a href="mailto:bastien.grenot@gmail.com" target="_blank" rel="noreferrer">
                        <img src="/Logo/gmail.svg" alt="Email" className="social-icon" />
                    </a>
                    {/* Bouton switch de thème */}
                    <div className="theme-switcher">
                        <label className="theme-switch">
                            <input
                                className="theme-toggle-checkbox"
                                type="checkbox"
                                checked={isDarkMode}
                                onChange={toggleTheme}
                            />
                            <div className="theme-toggle-slot">
                                <div className="sun-icon-wrapper">
                                    <div className="iconify sun-icon" data-icon="feather-sun" data-inline="false"></div>
                                </div>
                                <div className="theme-toggle-button"></div>
                                <div className="moon-icon-wrapper">
                                    <div className="iconify moon-icon" data-icon="feather-moon" data-inline="false"></div>
                                </div>
                            </div>
                        </label>
                    </div>
                </div>
            </nav>
        </header>
    );
}
